import requests

KONG_ADMIN_URL = 'http://localhost:8001'  # Replace with your Kong Admin URL

def create_service(service_name, service_url):
    service_data = {
        "name": service_name,
        "url": service_url
    }
    response = requests.post(f"{KONG_ADMIN_URL}/services", json=service_data)
    return response.json()

def create_route(service_name, route_paths):
    route_data = {
        "paths": route_paths,
        "service": {"name": service_name}
    }
    response = requests.post(f"{KONG_ADMIN_URL}/routes", json=route_data)
    return response.json()

def create_upstream(upstream_name):
    upstream_data = {
        "name": upstream_name
    }
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=upstream_data)
    return response.json()

def create_target(upstream_name, target_url):
    target_data = {
        "target": target_url,
        "weight": 100
    }
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets", json=target_data)
    return response.json()

def disable_rate_limiting():
    rate_limit_data = {
        "config": {
            "limit_by": "consumer",
            "minute": 0,
            "hour": 0,
            "day": 0
        }
    }
    response = requests.patch(f"{KONG_ADMIN_URL}/plugins/{rate_limit_plugin_id}", json=rate_limit_data)
    return response.json()

